# solution.py
"""CollaborativeDesignSuite
========================

A multi-agent collaborative design tool that lets a team of designers work
together on a shared digital canvas in real time.

The module is intentionally self-contained (standard library only) so it can be
dropped into any Python 3.8+ project.  It is organised into clearly separated
sub-systems, each one mapping to a requirement of the task:

    1. User Registration and Authentication ... :class:`AuthenticationSystem`
    2. Real-Time Collaboration Canvas ......... :class:`Canvas` /
                                                 :class:`CollaborationSession`
    3. Shape and Texture Tools ................ :mod:`Shapes` / :class:`Texture`
    4. Element Management and Organization .... :class:`Canvas` mixins
                                                 (group / align / arrange)
    5. Annotation and Commenting System ....... :class:`AnnotationSystem`
    6. Dependency Management .................. :class:`DependencyManager`

The :class:`CollaborativeDesignSuite` facade wires everything together and is
the public entry point of the application.

Design notes (Developer: create -> revise -> optimize)
------------------------------------------------------
* All mutating operations are guarded by re-entrant locks so the canvas can be
  edited concurrently by several designers (the "real-time" requirement).
* Every state change is published through a :class:`CollaborationSession` as an
  immutable :class:`Event`; subscribers receive these events synchronously,
  which is how remote participants stay in sync.
* Feature availability is governed by :class:`DependencyManager`, a small
  topological dependency graph, so a capability can never be used before its
  prerequisites are satisfied (e.g. textures require an existing shape and
  annotations require an active canvas).
"""

from __future__ import annotations

import hashlib
import hmac
import re
import secrets
import threading
import time
import uuid
from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from enum import Enum
from typing import Callable, Dict, Iterable, List, Optional, Sequence, Tuple

__all__ = [
    "CollaborativeDesignSuite",
    "DesignSuiteError",
    "AuthenticationError",
    "AuthorizationError",
    "DependencyError",
    "ValidationError",
    "NotFoundError",
    "Feature",
    "Alignment",
    "Arrange",
    "Texture",
    "Rectangle",
    "Circle",
    "Ellipse",
    "Line",
    "Polygon",
]


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------
class DesignSuiteError(Exception):
    """Base class for every error raised by the suite."""


class AuthenticationError(DesignSuiteError):
    """Raised when credentials are invalid or a session is unknown/expired."""


class AuthorizationError(DesignSuiteError):
    """Raised when an authenticated user is not allowed to perform an action."""


class DependencyError(DesignSuiteError):
    """Raised when an operation is attempted before its prerequisites are met."""


class ValidationError(DesignSuiteError):
    """Raised when user supplied data fails validation."""


class NotFoundError(DesignSuiteError):
    """Raised when a referenced entity (canvas, element, ...) does not exist."""


# ---------------------------------------------------------------------------
# Small utilities
# ---------------------------------------------------------------------------
def _new_id(prefix: str) -> str:
    """Return a short, collision-resistant identifier with a readable prefix."""
    return f"{prefix}_{uuid.uuid4().hex[:12]}"


def _now() -> float:
    return time.time()


# ===========================================================================
# Requirement 6 - Dependency Management
# ===========================================================================
class Feature(Enum):
    """The top level capabilities of the suite and their dependency order."""

    AUTHENTICATION = "authentication"
    COLLABORATION_CANVAS = "collaboration_canvas"
    SHAPE_TEXTURE_TOOLS = "shape_texture_tools"
    ELEMENT_MANAGEMENT = "element_management"
    ANNOTATION = "annotation"


class DependencyManager:
    """Tracks which :class:`Feature` capabilities are enabled.

    The prerequisite graph encodes the rules from the specification:

    * the collaboration canvas requires authentication,
    * shape & texture tools require an active canvas,
    * element management requires the shape & texture tools,
    * annotations require an active canvas.

    A feature can only be enabled once *all* of its prerequisites are enabled,
    guaranteeing a valid topological activation order.
    """

    _PREREQUISITES: Dict[Feature, Tuple[Feature, ...]] = {
        Feature.AUTHENTICATION: (),
        Feature.COLLABORATION_CANVAS: (Feature.AUTHENTICATION,),
        Feature.SHAPE_TEXTURE_TOOLS: (Feature.COLLABORATION_CANVAS,),
        Feature.ELEMENT_MANAGEMENT: (Feature.SHAPE_TEXTURE_TOOLS,),
        Feature.ANNOTATION: (Feature.COLLABORATION_CANVAS,),
    }

    def __init__(self) -> None:
        self._enabled: set = set()
        self._lock = threading.RLock()

    # -- queries ----------------------------------------------------------
    def is_enabled(self, feature: Feature) -> bool:
        with self._lock:
            return feature in self._enabled

    def prerequisites(self, feature: Feature) -> Tuple[Feature, ...]:
        return self._PREREQUISITES[feature]

    def enabled_features(self) -> List[Feature]:
        with self._lock:
            return sorted(self._enabled, key=lambda f: f.value)

    # -- mutations --------------------------------------------------------
    def enable(self, feature: Feature) -> None:
        """Enable *feature* after validating that every prerequisite is on."""
        with self._lock:
            if feature in self._enabled:
                return
            missing = [
                p for p in self._PREREQUISITES[feature] if p not in self._enabled
            ]
            if missing:
                names = ", ".join(m.value for m in missing)
                raise DependencyError(
                    f"Cannot enable '{feature.value}' until these features are "
                    f"active: {names}."
                )
            self._enabled.add(feature)

    def ensure(self, feature: Feature) -> None:
        """Enable *feature* and any missing prerequisites in dependency order."""
        with self._lock:
            for prereq in self._PREREQUISITES[feature]:
                self.ensure(prereq)
            self.enable(feature)

    def require(self, feature: Feature, action: Optional[str] = None) -> None:
        """Raise :class:`DependencyError` if *feature* is not enabled."""
        if not self.is_enabled(feature):
            what = action or "perform this action"
            raise DependencyError(
                f"Cannot {what}: the '{feature.value}' capability is not active "
                f"yet. Activate its prerequisites first."
            )

    def activation_order(self) -> List[Feature]:
        """Return a valid topological ordering of all known features."""
        order: List[Feature] = []
        seen: set = set()

        def visit(node: Feature) -> None:
            if node in seen:
                return
            seen.add(node)
            for prereq in self._PREREQUISITES[node]:
                visit(prereq)
            order.append(node)

        for feat in Feature:
            visit(feat)
        return order


# ===========================================================================
# Requirement 1 - User Registration and Authentication
# ===========================================================================
@dataclass
class User:
    """An application user. Passwords are never stored in clear text."""

    id: str
    username: str
    display_name: str
    _salt: bytes
    _pw_hash: bytes
    _iterations: int
    created_at: float = field(default_factory=_now)

    def verify_password(self, password: str) -> bool:
        candidate = hashlib.pbkdf2_hmac(
            "sha256", password.encode("utf-8"), self._salt, self._iterations
        )
        return hmac.compare_digest(candidate, self._pw_hash)

    def public(self) -> Dict[str, object]:
        """A safe, serialisable view that never leaks credential material."""
        return {
            "id": self.id,
            "username": self.username,
            "display_name": self.display_name,
            "created_at": self.created_at,
        }


@dataclass
class Session:
    token: str
    user_id: str
    created_at: float = field(default_factory=_now)
    last_seen: float = field(default_factory=_now)


class AuthenticationSystem:
    """Handles registration, login, logout and session validation."""

    _USERNAME_RE = re.compile(r"^[A-Za-z0-9_.-]{3,32}$")
    _PBKDF2_ITERATIONS = 200_000
    _SESSION_TTL_SECONDS = 8 * 60 * 60  # 8 hours

    def __init__(self) -> None:
        self._users_by_name: Dict[str, User] = {}
        self._users_by_id: Dict[str, User] = {}
        self._sessions: Dict[str, Session] = {}
        self._lock = threading.RLock()

    # -- registration -----------------------------------------------------
    def register(
        self, username: str, password: str, display_name: Optional[str] = None
    ) -> User:
        username = (username or "").strip()
        if not self._USERNAME_RE.match(username):
            raise ValidationError(
                "Username must be 3-32 characters using letters, digits, '_', "
                "'.' or '-'."
            )
        if not isinstance(password, str) or len(password) < 8:
            raise ValidationError("Password must be at least 8 characters long.")

        with self._lock:
            if username.lower() in self._users_by_name:
                raise ValidationError(f"Username '{username}' is already taken.")

            salt = secrets.token_bytes(16)
            pw_hash = hashlib.pbkdf2_hmac(
                "sha256", password.encode("utf-8"), salt, self._PBKDF2_ITERATIONS
            )
            user = User(
                id=_new_id("usr"),
                username=username,
                display_name=display_name or username,
                _salt=salt,
                _pw_hash=pw_hash,
                _iterations=self._PBKDF2_ITERATIONS,
            )
            self._users_by_name[username.lower()] = user
            self._users_by_id[user.id] = user
            return user

    # -- login / logout ---------------------------------------------------
    def login(self, username: str, password: str) -> str:
        with self._lock:
            user = self._users_by_name.get((username or "").strip().lower())
            if user is None or not user.verify_password(password or ""):
                # Identical error for both cases to avoid user enumeration.
                raise AuthenticationError("Invalid username or password.")
            token = secrets.token_urlsafe(24)
            self._sessions[token] = Session(token=token, user_id=user.id)
            return token

    def logout(self, token: str) -> None:
        with self._lock:
            self._sessions.pop(token, None)

    # -- validation -------------------------------------------------------
    def authenticate(self, token: str) -> User:
        """Return the :class:`User` for *token* or raise AuthenticationError."""
        with self._lock:
            session = self._sessions.get(token)
            if session is None:
                raise AuthenticationError("Not authenticated: unknown session token.")
            if _now() - session.created_at > self._SESSION_TTL_SECONDS:
                self._sessions.pop(token, None)
                raise AuthenticationError("Session expired, please log in again.")
            session.last_seen = _now()
            return self._users_by_id[session.user_id]

    def get_user(self, user_id: str) -> Optional[User]:
        return self._users_by_id.get(user_id)

    def list_users(self) -> List[Dict[str, object]]:
        with self._lock:
            return [u.public() for u in self._users_by_id.values()]


# ===========================================================================
# Requirement 3 - Shape and Texture Tools
# ===========================================================================
_NAMED_COLORS = {
    "black": "#000000",
    "white": "#FFFFFF",
    "red": "#FF0000",
    "green": "#008000",
    "blue": "#0000FF",
    "yellow": "#FFFF00",
    "cyan": "#00FFFF",
    "magenta": "#FF00FF",
    "gray": "#808080",
    "grey": "#808080",
    "orange": "#FFA500",
    "purple": "#800080",
}


def normalize_color(color) -> str:
    """Validate and normalise *color* to an upper-case ``#RRGGBB`` string.

    Accepts named colours, ``#RGB`` / ``#RRGGBB`` strings and ``(r, g, b)``
    integer tuples.
    """
    if isinstance(color, (tuple, list)):
        if len(color) != 3 or not all(
            isinstance(c, int) and 0 <= c <= 255 for c in color
        ):
            raise ValidationError("RGB colour must be three integers in 0..255.")
        return "#{:02X}{:02X}{:02X}".format(*color)

    if isinstance(color, str):
        key = color.strip().lower()
        if key in _NAMED_COLORS:
            return _NAMED_COLORS[key]
        text = color.strip()
        if re.fullmatch(r"#[0-9a-fA-F]{6}", text):
            return text.upper()
        if re.fullmatch(r"#[0-9a-fA-F]{3}", text):
            r, g, b = text[1], text[2], text[3]
            return f"#{r}{r}{g}{g}{b}{b}".upper()
    raise ValidationError(f"Unsupported colour value: {color!r}.")


class TextureType(Enum):
    SOLID = "solid"
    GRADIENT = "gradient"
    PATTERN = "pattern"


@dataclass(frozen=True)
class Texture:
    """An immutable description of how a shape is filled."""

    type: TextureType
    colors: Tuple[str, ...] = ()
    angle: float = 0.0
    pattern: Optional[str] = None
    scale: float = 1.0

    _PATTERNS = frozenset(
        {"dots", "stripes", "grid", "checker", "cross-hatch", "noise"}
    )

    # -- factory helpers --------------------------------------------------
    @classmethod
    def solid(cls, color) -> "Texture":
        return cls(type=TextureType.SOLID, colors=(normalize_color(color),))

    @classmethod
    def gradient(cls, colors: Sequence, angle: float = 0.0) -> "Texture":
        if len(colors) < 2:
            raise ValidationError("A gradient needs at least two colours.")
        norm = tuple(normalize_color(c) for c in colors)
        return cls(type=TextureType.GRADIENT, colors=norm, angle=float(angle))

    @classmethod
    def pattern(cls, name: str, color="black", scale: float = 1.0) -> "Texture":
        if name not in cls._PATTERNS:
            allowed = ", ".join(sorted(cls._PATTERNS))
            raise ValidationError(f"Unknown pattern '{name}'. Choose from: {allowed}.")
        if scale <= 0:
            raise ValidationError("Pattern scale must be positive.")
        return cls(
            type=TextureType.PATTERN,
            colors=(normalize_color(color),),
            pattern=name,
            scale=float(scale),
        )

    def to_dict(self) -> Dict[str, object]:
        return {
            "type": self.type.value,
            "colors": list(self.colors),
            "angle": self.angle,
            "pattern": self.pattern,
            "scale": self.scale,
        }


@dataclass(frozen=True)
class BoundingBox:
    min_x: float
    min_y: float
    max_x: float
    max_y: float

    @property
    def width(self) -> float:
        return self.max_x - self.min_x

    @property
    def height(self) -> float:
        return self.max_y - self.min_y

    @property
    def center_x(self) -> float:
        return (self.min_x + self.max_x) / 2.0

    @property
    def center_y(self) -> float:
        return (self.min_y + self.max_y) / 2.0


class Element(ABC):
    """Base class for every drawable object placed on the canvas."""

    def __init__(self, owner_id: str, name: Optional[str] = None) -> None:
        self.id = _new_id("el")
        self.owner_id = owner_id
        self.name = name or self.id
        self.z_index = 0
        self.group_id: Optional[str] = None
        self.locked = False
        self.visible = True
        self.texture: Optional[Texture] = None
        self.created_at = _now()
        self.updated_at = self.created_at

    # -- geometry (subclass responsibility) ------------------------------
    @abstractmethod
    def bounding_box(self) -> BoundingBox: ...

    @abstractmethod
    def translate(self, dx: float, dy: float) -> None: ...

    @abstractmethod
    def _geometry(self) -> Dict[str, object]: ...

    # -- shared behaviour -------------------------------------------------
    def move_to(self, x: float, y: float) -> None:
        """Move the element so its bounding-box top-left sits at ``(x, y)``."""
        box = self.bounding_box()
        self.translate(x - box.min_x, y - box.min_y)

    def touch(self) -> None:
        self.updated_at = _now()

    def to_dict(self) -> Dict[str, object]:
        data = {
            "id": self.id,
            "kind": type(self).__name__.lower(),
            "name": self.name,
            "owner_id": self.owner_id,
            "z_index": self.z_index,
            "group_id": self.group_id,
            "locked": self.locked,
            "visible": self.visible,
            "texture": self.texture.to_dict() if self.texture else None,
            "geometry": self._geometry(),
        }
        return data


class Rectangle(Element):
    def __init__(self, owner_id, x, y, width, height, name=None):
        super().__init__(owner_id, name)
        if width <= 0 or height <= 0:
            raise ValidationError("Rectangle width and height must be positive.")
        self.x, self.y = float(x), float(y)
        self.width, self.height = float(width), float(height)

    def bounding_box(self) -> BoundingBox:
        return BoundingBox(self.x, self.y, self.x + self.width, self.y + self.height)

    def translate(self, dx, dy) -> None:
        self.x += dx
        self.y += dy
        self.touch()

    def _geometry(self):
        return {"x": self.x, "y": self.y, "width": self.width, "height": self.height}


class Circle(Element):
    def __init__(self, owner_id, cx, cy, radius, name=None):
        super().__init__(owner_id, name)
        if radius <= 0:
            raise ValidationError("Circle radius must be positive.")
        self.cx, self.cy, self.radius = float(cx), float(cy), float(radius)

    def bounding_box(self) -> BoundingBox:
        r = self.radius
        return BoundingBox(self.cx - r, self.cy - r, self.cx + r, self.cy + r)

    def translate(self, dx, dy) -> None:
        self.cx += dx
        self.cy += dy
        self.touch()

    def _geometry(self):
        return {"cx": self.cx, "cy": self.cy, "radius": self.radius}


class Ellipse(Element):
    def __init__(self, owner_id, cx, cy, rx, ry, name=None):
        super().__init__(owner_id, name)
        if rx <= 0 or ry <= 0:
            raise ValidationError("Ellipse radii must be positive.")
        self.cx, self.cy = float(cx), float(cy)
        self.rx, self.ry = float(rx), float(ry)

    def bounding_box(self) -> BoundingBox:
        return BoundingBox(
            self.cx - self.rx, self.cy - self.ry, self.cx + self.rx, self.cy + self.ry
        )

    def translate(self, dx, dy) -> None:
        self.cx += dx
        self.cy += dy
        self.touch()

    def _geometry(self):
        return {"cx": self.cx, "cy": self.cy, "rx": self.rx, "ry": self.ry}


class Line(Element):
    def __init__(self, owner_id, x1, y1, x2, y2, name=None):
        super().__init__(owner_id, name)
        self.x1, self.y1 = float(x1), float(y1)
        self.x2, self.y2 = float(x2), float(y2)
        if (self.x1, self.y1) == (self.x2, self.y2):
            raise ValidationError("A line needs two distinct endpoints.")

    def bounding_box(self) -> BoundingBox:
        return BoundingBox(
            min(self.x1, self.x2),
            min(self.y1, self.y2),
            max(self.x1, self.x2),
            max(self.y1, self.y2),
        )

    def translate(self, dx, dy) -> None:
        self.x1 += dx
        self.y1 += dy
        self.x2 += dx
        self.y2 += dy
        self.touch()

    def _geometry(self):
        return {"x1": self.x1, "y1": self.y1, "x2": self.x2, "y2": self.y2}


class Polygon(Element):
    def __init__(self, owner_id, points: Sequence[Tuple[float, float]], name=None):
        super().__init__(owner_id, name)
        pts = [(float(px), float(py)) for px, py in points]
        if len(pts) < 3:
            raise ValidationError("A polygon needs at least three points.")
        self.points: List[Tuple[float, float]] = pts

    def bounding_box(self) -> BoundingBox:
        xs = [p[0] for p in self.points]
        ys = [p[1] for p in self.points]
        return BoundingBox(min(xs), min(ys), max(xs), max(ys))

    def translate(self, dx, dy) -> None:
        self.points = [(px + dx, py + dy) for px, py in self.points]
        self.touch()

    def _geometry(self):
        return {"points": [list(p) for p in self.points]}


# Factory mapping used by the facade to build shapes from a type name.
_SHAPE_FACTORY: Dict[str, Callable[..., Element]] = {
    "rectangle": Rectangle,
    "circle": Circle,
    "ellipse": Ellipse,
    "line": Line,
    "polygon": Polygon,
}


# ===========================================================================
# Requirement 4 - Element Management and Organization
# ===========================================================================
class Alignment(Enum):
    LEFT = "left"
    RIGHT = "right"
    TOP = "top"
    BOTTOM = "bottom"
    CENTER_X = "center_x"  # align horizontal centres (same center_x)
    CENTER_Y = "center_y"  # align vertical centres (same center_y)


class Arrange(Enum):
    BRING_TO_FRONT = "bring_to_front"
    SEND_TO_BACK = "send_to_back"
    BRING_FORWARD = "bring_forward"
    SEND_BACKWARD = "send_backward"


@dataclass
class Group:
    id: str
    owner_id: str
    member_ids: List[str]
    name: str

    def to_dict(self) -> Dict[str, object]:
        return {
            "id": self.id,
            "owner_id": self.owner_id,
            "name": self.name,
            "member_ids": list(self.member_ids),
        }


# ===========================================================================
# Requirement 5 - Annotation and Commenting System
# ===========================================================================
@dataclass
class Reply:
    author_id: str
    text: str
    created_at: float = field(default_factory=_now)

    def to_dict(self):
        return {
            "author_id": self.author_id,
            "text": self.text,
            "created_at": self.created_at,
        }


@dataclass
class Annotation:
    id: str
    author_id: str
    text: str
    target_element_id: Optional[str]
    x: float
    y: float
    created_at: float = field(default_factory=_now)
    resolved: bool = False
    replies: List[Reply] = field(default_factory=list)

    def to_dict(self) -> Dict[str, object]:
        return {
            "id": self.id,
            "author_id": self.author_id,
            "text": self.text,
            "target_element_id": self.target_element_id,
            "position": {"x": self.x, "y": self.y},
            "created_at": self.created_at,
            "resolved": self.resolved,
            "replies": [r.to_dict() for r in self.replies],
        }


class AnnotationSystem:
    """Stores annotations (with threaded replies) for a single canvas."""

    def __init__(self) -> None:
        self._annotations: Dict[str, Annotation] = {}
        self._lock = threading.RLock()

    def add(
        self,
        author_id: str,
        text: str,
        target_element_id: Optional[str],
        x: float,
        y: float,
    ) -> Annotation:
        if not text or not text.strip():
            raise ValidationError("Annotation text must not be empty.")
        with self._lock:
            ann = Annotation(
                id=_new_id("ann"),
                author_id=author_id,
                text=text.strip(),
                target_element_id=target_element_id,
                x=float(x),
                y=float(y),
            )
            self._annotations[ann.id] = ann
            return ann

    def get(self, annotation_id: str) -> Annotation:
        with self._lock:
            ann = self._annotations.get(annotation_id)
            if ann is None:
                raise NotFoundError(f"Annotation '{annotation_id}' does not exist.")
            return ann

    def reply(self, annotation_id: str, author_id: str, text: str) -> Reply:
        if not text or not text.strip():
            raise ValidationError("Reply text must not be empty.")
        with self._lock:
            ann = self.get(annotation_id)
            reply = Reply(author_id=author_id, text=text.strip())
            ann.replies.append(reply)
            return reply

    def resolve(self, annotation_id: str) -> Annotation:
        with self._lock:
            ann = self.get(annotation_id)
            ann.resolved = True
            return ann

    def list(self, include_resolved: bool = True) -> List[Annotation]:
        with self._lock:
            return [
                a
                for a in self._annotations.values()
                if include_resolved or not a.resolved
            ]

    def for_element(self, element_id: str) -> List[Annotation]:
        with self._lock:
            return [
                a
                for a in self._annotations.values()
                if a.target_element_id == element_id
            ]


# ===========================================================================
# Requirement 2 - Real-Time Collaboration Canvas
# ===========================================================================
class EventType(Enum):
    USER_JOINED = "user_joined"
    USER_LEFT = "user_left"
    ELEMENT_ADDED = "element_added"
    ELEMENT_REMOVED = "element_removed"
    ELEMENT_MOVED = "element_moved"
    TEXTURE_APPLIED = "texture_applied"
    ELEMENTS_GROUPED = "elements_grouped"
    ELEMENTS_UNGROUPED = "elements_ungrouped"
    ELEMENTS_ALIGNED = "elements_aligned"
    ELEMENT_ARRANGED = "element_arranged"
    ANNOTATION_ADDED = "annotation_added"
    ANNOTATION_REPLIED = "annotation_replied"
    ANNOTATION_RESOLVED = "annotation_resolved"


@dataclass(frozen=True)
class Event:
    """An immutable record of something that happened on the canvas."""

    seq: int
    type: EventType
    actor_id: str
    payload: Dict[str, object]
    timestamp: float

    def to_dict(self) -> Dict[str, object]:
        return {
            "seq": self.seq,
            "type": self.type.value,
            "actor_id": self.actor_id,
            "payload": dict(self.payload),
            "timestamp": self.timestamp,
        }


EventCallback = Callable[[Event], None]


class CollaborationSession:
    """Coordinates the designers connected to one canvas.

    The session keeps an ordered, append-only event log (the source of truth
    for synchronisation) and notifies every subscriber as events occur, which
    is what makes editing feel real time for all participants.
    """

    def __init__(self, canvas_id: str) -> None:
        self.id = _new_id("ses")
        self.canvas_id = canvas_id
        self._participants: Dict[str, float] = {}  # user_id -> joined_at
        self._subscribers: Dict[str, EventCallback] = {}
        self._events: List[Event] = []
        self._seq = 0
        self._lock = threading.RLock()

    # -- presence ---------------------------------------------------------
    def join(self, user_id: str, on_event: Optional[EventCallback] = None) -> None:
        with self._lock:
            first_time = user_id not in self._participants
            self._participants[user_id] = _now()
            if on_event is not None:
                self._subscribers[user_id] = on_event
        if first_time:
            self.broadcast(EventType.USER_JOINED, user_id, {"user_id": user_id})

    def leave(self, user_id: str) -> None:
        with self._lock:
            existed = self._participants.pop(user_id, None) is not None
            self._subscribers.pop(user_id, None)
        if existed:
            self.broadcast(EventType.USER_LEFT, user_id, {"user_id": user_id})

    def is_participant(self, user_id: str) -> bool:
        with self._lock:
            return user_id in self._participants

    def participants(self) -> List[str]:
        with self._lock:
            return list(self._participants.keys())

    # -- event distribution ----------------------------------------------
    def broadcast(
        self, event_type: EventType, actor_id: str, payload: Dict[str, object]
    ) -> Event:
        with self._lock:
            self._seq += 1
            event = Event(
                seq=self._seq,
                type=event_type,
                actor_id=actor_id,
                payload=dict(payload),
                timestamp=_now(),
            )
            self._events.append(event)
            # Copy subscribers so callbacks run outside the lock (no deadlocks).
            subscribers = list(self._subscribers.items())

        for user_id, callback in subscribers:
            try:
                callback(event)
            except Exception:  # pragma: no cover - a faulty client must not
                # break collaboration for everyone else.
                continue
        return event

    def history(self, since_seq: int = 0) -> List[Event]:
        with self._lock:
            return [e for e in self._events if e.seq > since_seq]


class Canvas:
    """A shared drawing surface holding elements, groups and annotations.

    The canvas owns the low-level, thread-safe data operations and publishes an
    :class:`Event` through its :class:`CollaborationSession` after every change.
    Higher-level permission and dependency checks live in the facade.
    """

    def __init__(self, canvas_id: str, name: str, owner_id: str) -> None:
        self.id = canvas_id
        self.name = name
        self.owner_id = owner_id
        self.created_at = _now()
        self._elements: Dict[str, Element] = {}
        self._groups: Dict[str, Group] = {}
        self._z_order: List[str] = []  # element ids, back -> front
        self.annotations = AnnotationSystem()
        self.session = CollaborationSession(canvas_id)
        self._lock = threading.RLock()

    # -- lookups ----------------------------------------------------------
    def get_element(self, element_id: str) -> Element:
        with self._lock:
            el = self._elements.get(element_id)
            if el is None:
                raise NotFoundError(f"Element '{element_id}' does not exist.")
            return el

    def get_group(self, group_id: str) -> Group:
        with self._lock:
            grp = self._groups.get(group_id)
            if grp is None:
                raise NotFoundError(f"Group '{group_id}' does not exist.")
            return grp

    def has_elements(self) -> bool:
        with self._lock:
            return bool(self._elements)

    def elements_in_order(self) -> List[Element]:
        with self._lock:
            return [self._elements[eid] for eid in self._z_order]

    def _next_z(self) -> int:
        return len(self._z_order)

    def _reindex(self) -> None:
        for index, eid in enumerate(self._z_order):
            self._elements[eid].z_index = index

    # -- element CRUD -----------------------------------------------------
    def add_element(self, element: Element) -> Element:
        with self._lock:
            self._elements[element.id] = element
            self._z_order.append(element.id)
            element.z_index = self._next_z() - 1
        self.session.broadcast(
            EventType.ELEMENT_ADDED,
            element.owner_id,
            {"element": element.to_dict()},
        )
        return element

    def remove_element(self, actor_id: str, element_id: str) -> None:
        with self._lock:
            element = self.get_element(element_id)
            self._elements.pop(element_id)
            self._z_order.remove(element_id)
            if element.group_id:
                grp = self._groups.get(element.group_id)
                if grp and element_id in grp.member_ids:
                    grp.member_ids.remove(element_id)
            self._reindex()
        self.session.broadcast(
            EventType.ELEMENT_REMOVED, actor_id, {"element_id": element_id}
        )

    def move_element(self, actor_id: str, element_id: str, x: float, y: float) -> None:
        with self._lock:
            element = self.get_element(element_id)
            if element.locked:
                raise AuthorizationError(f"Element '{element_id}' is locked.")
            element.move_to(x, y)
            box = element.bounding_box()
        self.session.broadcast(
            EventType.ELEMENT_MOVED,
            actor_id,
            {"element_id": element_id, "x": box.min_x, "y": box.min_y},
        )

    # -- textures ---------------------------------------------------------
    def apply_texture(self, actor_id: str, element_id: str, texture: Texture) -> None:
        with self._lock:
            element = self.get_element(element_id)
            if element.locked:
                raise AuthorizationError(f"Element '{element_id}' is locked.")
            element.texture = texture
            element.touch()
        self.session.broadcast(
            EventType.TEXTURE_APPLIED,
            actor_id,
            {"element_id": element_id, "texture": texture.to_dict()},
        )

    # -- grouping ---------------------------------------------------------
    def group_elements(
        self, actor_id: str, element_ids: Sequence[str], name: Optional[str] = None
    ) -> Group:
        with self._lock:
            unique_ids = list(dict.fromkeys(element_ids))
            if len(unique_ids) < 2:
                raise ValidationError("Grouping requires at least two elements.")
            members = [self.get_element(eid) for eid in unique_ids]
            group = Group(
                id=_new_id("grp"),
                owner_id=actor_id,
                member_ids=unique_ids,
                name=name or "group",
            )
            self._groups[group.id] = group
            for el in members:
                el.group_id = group.id
        self.session.broadcast(
            EventType.ELEMENTS_GROUPED,
            actor_id,
            {"group_id": group.id, "member_ids": unique_ids},
        )
        return group

    def ungroup(self, actor_id: str, group_id: str) -> None:
        with self._lock:
            group = self.get_group(group_id)
            for eid in group.member_ids:
                el = self._elements.get(eid)
                if el is not None:
                    el.group_id = None
            self._groups.pop(group_id)
        self.session.broadcast(
            EventType.ELEMENTS_UNGROUPED, actor_id, {"group_id": group_id}
        )

    # -- alignment --------------------------------------------------------
    def align_elements(
        self, actor_id: str, element_ids: Sequence[str], alignment: Alignment
    ) -> None:
        with self._lock:
            unique_ids = list(dict.fromkeys(element_ids))
            if len(unique_ids) < 2:
                raise ValidationError("Alignment requires at least two elements.")
            items = [(eid, self.get_element(eid)) for eid in unique_ids]
            boxes = {eid: el.bounding_box() for eid, el in items}

            if alignment is Alignment.LEFT:
                target = min(b.min_x for b in boxes.values())
                for eid, el in items:
                    el.translate(target - boxes[eid].min_x, 0)
            elif alignment is Alignment.RIGHT:
                target = max(b.max_x for b in boxes.values())
                for eid, el in items:
                    el.translate(target - boxes[eid].max_x, 0)
            elif alignment is Alignment.TOP:
                target = min(b.min_y for b in boxes.values())
                for eid, el in items:
                    el.translate(0, target - boxes[eid].min_y)
            elif alignment is Alignment.BOTTOM:
                target = max(b.max_y for b in boxes.values())
                for eid, el in items:
                    el.translate(0, target - boxes[eid].max_y)
            elif alignment is Alignment.CENTER_X:
                target = sum(b.center_x for b in boxes.values()) / len(boxes)
                for eid, el in items:
                    el.translate(target - boxes[eid].center_x, 0)
            elif alignment is Alignment.CENTER_Y:
                target = sum(b.center_y for b in boxes.values()) / len(boxes)
                for eid, el in items:
                    el.translate(0, target - boxes[eid].center_y)
            else:  # pragma: no cover - defensive
                raise ValidationError(f"Unknown alignment '{alignment}'.")
        self.session.broadcast(
            EventType.ELEMENTS_ALIGNED,
            actor_id,
            {"element_ids": unique_ids, "alignment": alignment.value},
        )

    # -- z-order arrangement ---------------------------------------------
    def arrange_element(self, actor_id: str, element_id: str, arrange: Arrange) -> None:
        with self._lock:
            if element_id not in self._elements:
                raise NotFoundError(f"Element '{element_id}' does not exist.")
            order = self._z_order
            index = order.index(element_id)
            order.pop(index)
            if arrange is Arrange.BRING_TO_FRONT:
                order.append(element_id)
            elif arrange is Arrange.SEND_TO_BACK:
                order.insert(0, element_id)
            elif arrange is Arrange.BRING_FORWARD:
                order.insert(min(index + 1, len(order)), element_id)
            elif arrange is Arrange.SEND_BACKWARD:
                order.insert(max(index - 1, 0), element_id)
            else:  # pragma: no cover - defensive
                order.insert(index, element_id)
                raise ValidationError(f"Unknown arrange action '{arrange}'.")
            self._reindex()
            new_index = self._z_order.index(element_id)
        self.session.broadcast(
            EventType.ELEMENT_ARRANGED,
            actor_id,
            {"element_id": element_id, "action": arrange.value, "z_index": new_index},
        )

    # -- serialisation ----------------------------------------------------
    def to_dict(self) -> Dict[str, object]:
        with self._lock:
            return {
                "id": self.id,
                "name": self.name,
                "owner_id": self.owner_id,
                "created_at": self.created_at,
                "elements": [el.to_dict() for el in self.elements_in_order()],
                "groups": [g.to_dict() for g in self._groups.values()],
                "annotations": [a.to_dict() for a in self.annotations.list()],
                "participants": self.session.participants(),
            }


# ===========================================================================
# Facade - CollaborativeDesignSuite
# ===========================================================================
class CollaborativeDesignSuite:
    """Public entry point that ties every sub-system together.

    Typical flow::

        suite = CollaborativeDesignSuite()
        suite.register("ada", "supersecret")
        token = suite.login("ada", "supersecret")
        canvas_id = suite.create_canvas(token, "Logo")
        rect = suite.add_shape(token, canvas_id, "rectangle",
                               x=0, y=0, width=100, height=60)
        suite.apply_texture(token, canvas_id, rect,
                            Texture.solid("#3366FF"))
    """

    def __init__(self) -> None:
        self.auth = AuthenticationSystem()
        self.dependencies = DependencyManager()
        self._canvases: Dict[str, Canvas] = {}
        self._lock = threading.RLock()
        # Authentication is the foundational capability and is always on.
        self.dependencies.enable(Feature.AUTHENTICATION)

    # ------------------------------------------------------------------
    # Requirement 1 - authentication API
    # ------------------------------------------------------------------
    def register(
        self, username: str, password: str, display_name: Optional[str] = None
    ) -> Dict[str, object]:
        user = self.auth.register(username, password, display_name)
        return user.public()

    def login(self, username: str, password: str) -> str:
        return self.auth.login(username, password)

    def logout(self, token: str) -> None:
        self.auth.logout(token)

    def list_users(self) -> List[Dict[str, object]]:
        return self.auth.list_users()

    # -- internal helpers -------------------------------------------------
    def _user(self, token: str) -> User:
        return self.auth.authenticate(token)

    def _get_canvas(self, canvas_id: str) -> Canvas:
        with self._lock:
            canvas = self._canvases.get(canvas_id)
        if canvas is None:
            raise NotFoundError(f"Canvas '{canvas_id}' does not exist.")
        return canvas

    def _require_participant(self, canvas: Canvas, user: User) -> None:
        if not canvas.session.is_participant(user.id):
            raise AuthorizationError(
                f"User '{user.username}' must join canvas '{canvas.id}' before "
                f"editing it."
            )

    # ------------------------------------------------------------------
    # Requirement 2 - collaboration canvas API
    # ------------------------------------------------------------------
    def create_canvas(self, token: str, name: str) -> str:
        user = self._user(token)
        self.dependencies.require(Feature.AUTHENTICATION, "create a canvas")
        if not name or not name.strip():
            raise ValidationError("Canvas name must not be empty.")

        # Activating a canvas brings the dependent capabilities online in a
        # valid topological order (canvas -> tools -> element mgmt; canvas ->
        # annotation).
        self.dependencies.ensure(Feature.COLLABORATION_CANVAS)
        self.dependencies.ensure(Feature.SHAPE_TEXTURE_TOOLS)
        self.dependencies.ensure(Feature.ELEMENT_MANAGEMENT)
        self.dependencies.ensure(Feature.ANNOTATION)

        canvas = Canvas(_new_id("cnv"), name.strip(), user.id)
        with self._lock:
            self._canvases[canvas.id] = canvas
        # The creator is automatically a participant.
        canvas.session.join(user.id)
        return canvas.id

    def join_canvas(
        self, token: str, canvas_id: str, on_event: Optional[EventCallback] = None
    ) -> str:
        user = self._user(token)
        self.dependencies.require(Feature.COLLABORATION_CANVAS, "join a canvas")
        canvas = self._get_canvas(canvas_id)
        canvas.session.join(user.id, on_event)
        return canvas.session.id

    def leave_canvas(self, token: str, canvas_id: str) -> None:
        user = self._user(token)
        canvas = self._get_canvas(canvas_id)
        canvas.session.leave(user.id)

    def participants(self, token: str, canvas_id: str) -> List[str]:
        self._user(token)
        return self._get_canvas(canvas_id).session.participants()

    def event_history(
        self, token: str, canvas_id: str, since_seq: int = 0
    ) -> List[Dict[str, object]]:
        self._user(token)
        canvas = self._get_canvas(canvas_id)
        return [e.to_dict() for e in canvas.session.history(since_seq)]

    # ------------------------------------------------------------------
    # Requirement 3 - shape & texture tools API
    # ------------------------------------------------------------------
    def add_shape(self, token: str, canvas_id: str, shape_type: str, **params) -> str:
        user = self._user(token)
        self.dependencies.require(Feature.SHAPE_TEXTURE_TOOLS, "draw a shape")
        canvas = self._get_canvas(canvas_id)
        self._require_participant(canvas, user)

        factory = _SHAPE_FACTORY.get(shape_type.lower())
        if factory is None:
            allowed = ", ".join(sorted(_SHAPE_FACTORY))
            raise ValidationError(
                f"Unknown shape type '{shape_type}'. Choose from: {allowed}."
            )
        try:
            element = factory(owner_id=user.id, **params)
        except TypeError as exc:
            raise ValidationError(
                f"Invalid parameters for '{shape_type}': {exc}"
            ) from exc
        canvas.add_element(element)
        return element.id

    def apply_texture(
        self, token: str, canvas_id: str, element_id: str, texture: Texture
    ) -> None:
        user = self._user(token)
        self.dependencies.require(Feature.SHAPE_TEXTURE_TOOLS, "apply a texture")
        if not isinstance(texture, Texture):
            raise ValidationError("texture must be a Texture instance.")
        canvas = self._get_canvas(canvas_id)
        self._require_participant(canvas, user)

        # Explicit dependency from the spec: textures need an existing shape.
        if not canvas.has_elements():
            raise DependencyError(
                "Cannot apply a texture before any shape has been created on the "
                "canvas."
            )
        canvas.get_element(element_id)  # validates existence
        canvas.apply_texture(user.id, element_id, texture)

    def move_shape(
        self, token: str, canvas_id: str, element_id: str, x: float, y: float
    ) -> None:
        user = self._user(token)
        self.dependencies.require(Feature.SHAPE_TEXTURE_TOOLS, "move a shape")
        canvas = self._get_canvas(canvas_id)
        self._require_participant(canvas, user)
        canvas.move_element(user.id, element_id, x, y)

    def remove_shape(self, token: str, canvas_id: str, element_id: str) -> None:
        user = self._user(token)
        self.dependencies.require(Feature.SHAPE_TEXTURE_TOOLS, "remove a shape")
        canvas = self._get_canvas(canvas_id)
        self._require_participant(canvas, user)
        canvas.remove_element(user.id, element_id)

    # ------------------------------------------------------------------
    # Requirement 4 - element management API
    # ------------------------------------------------------------------
    def group_elements(
        self,
        token: str,
        canvas_id: str,
        element_ids: Sequence[str],
        name: Optional[str] = None,
    ) -> str:
        user = self._user(token)
        self.dependencies.require(Feature.ELEMENT_MANAGEMENT, "group elements")
        canvas = self._get_canvas(canvas_id)
        self._require_participant(canvas, user)
        return canvas.group_elements(user.id, element_ids, name).id

    def ungroup(self, token: str, canvas_id: str, group_id: str) -> None:
        user = self._user(token)
        self.dependencies.require(Feature.ELEMENT_MANAGEMENT, "ungroup elements")
        canvas = self._get_canvas(canvas_id)
        self._require_participant(canvas, user)
        canvas.ungroup(user.id, group_id)

    def align_elements(
        self,
        token: str,
        canvas_id: str,
        element_ids: Sequence[str],
        alignment: Alignment,
    ) -> None:
        user = self._user(token)
        self.dependencies.require(Feature.ELEMENT_MANAGEMENT, "align elements")
        if not isinstance(alignment, Alignment):
            raise ValidationError("alignment must be an Alignment value.")
        canvas = self._get_canvas(canvas_id)
        self._require_participant(canvas, user)
        canvas.align_elements(user.id, element_ids, alignment)

    def arrange_element(
        self, token: str, canvas_id: str, element_id: str, arrange: Arrange
    ) -> None:
        user = self._user(token)
        self.dependencies.require(Feature.ELEMENT_MANAGEMENT, "arrange an element")
        if not isinstance(arrange, Arrange):
            raise ValidationError("arrange must be an Arrange value.")
        canvas = self._get_canvas(canvas_id)
        self._require_participant(canvas, user)
        canvas.arrange_element(user.id, element_id, arrange)

    # ------------------------------------------------------------------
    # Requirement 5 - annotation API
    # ------------------------------------------------------------------
    def add_annotation(
        self,
        token: str,
        canvas_id: str,
        text: str,
        element_id: Optional[str] = None,
        x: float = 0.0,
        y: float = 0.0,
    ) -> str:
        user = self._user(token)
        # Explicit dependency from the spec: annotations require an active
        # collaboration canvas.
        self.dependencies.require(Feature.ANNOTATION, "add an annotation")
        canvas = self._get_canvas(canvas_id)
        self._require_participant(canvas, user)

        if element_id is not None:
            element = canvas.get_element(element_id)
            box = element.bounding_box()
            # Default the marker to the element centre when no point is given.
            if x == 0.0 and y == 0.0:
                x, y = box.center_x, box.center_y

        annotation = canvas.annotations.add(user.id, text, element_id, x, y)
        canvas.session.broadcast(
            EventType.ANNOTATION_ADDED,
            user.id,
            {"annotation": annotation.to_dict()},
        )
        return annotation.id

    def reply_annotation(
        self, token: str, canvas_id: str, annotation_id: str, text: str
    ) -> None:
        user = self._user(token)
        self.dependencies.require(Feature.ANNOTATION, "reply to an annotation")
        canvas = self._get_canvas(canvas_id)
        self._require_participant(canvas, user)
        canvas.annotations.reply(annotation_id, user.id, text)
        canvas.session.broadcast(
            EventType.ANNOTATION_REPLIED,
            user.id,
            {"annotation_id": annotation_id},
        )

    def resolve_annotation(
        self, token: str, canvas_id: str, annotation_id: str
    ) -> None:
        user = self._user(token)
        self.dependencies.require(Feature.ANNOTATION, "resolve an annotation")
        canvas = self._get_canvas(canvas_id)
        self._require_participant(canvas, user)
        canvas.annotations.resolve(annotation_id)
        canvas.session.broadcast(
            EventType.ANNOTATION_RESOLVED,
            user.id,
            {"annotation_id": annotation_id},
        )

    def list_annotations(
        self, token: str, canvas_id: str, include_resolved: bool = True
    ) -> List[Dict[str, object]]:
        self._user(token)
        canvas = self._get_canvas(canvas_id)
        return [a.to_dict() for a in canvas.annotations.list(include_resolved)]

    # ------------------------------------------------------------------
    # Misc / introspection
    # ------------------------------------------------------------------
    def export_canvas(self, token: str, canvas_id: str) -> Dict[str, object]:
        self._user(token)
        return self._get_canvas(canvas_id).to_dict()

    def feature_status(self) -> Dict[str, bool]:
        return {
            feat.value: self.dependencies.is_enabled(feat) for feat in Feature
        }


