def _demo() -> None:
    """Exercise every feature and assert the expected behaviour."""
    print("=" * 70)
    print("CollaborativeDesignSuite - demonstration")
    print("=" * 70)

    suite = CollaborativeDesignSuite()

    # -- Requirement 6: dependency rules are enforced up front ------------
    print("\n[Dependency] Feature activation order:",
          [f.value for f in suite.dependencies.activation_order()])

    # -- Requirement 1: registration & authentication ---------------------
    suite.register("ada", "lovelace-1843", display_name="Ada Lovelace")
    suite.register("grace", "hopper-cobol-7")
    print("\n[Auth] Registered users:", [u["username"] for u in suite.list_users()])

    # Duplicate username and weak password are rejected.
    for bad in (("ada", "another-pass"), ("newbie", "short")):
        try:
            suite.register(*bad)
            raise AssertionError("expected ValidationError")
        except ValidationError as exc:
            print(f"[Auth] Rejected registration {bad[0]!r}: {exc}")

    # Wrong password fails, correct password yields a token.
    try:
        suite.login("ada", "wrong")
        raise AssertionError("expected AuthenticationError")
    except AuthenticationError as exc:
        print("[Auth] Bad login correctly rejected:", exc)

    ada_token = suite.login("ada", "lovelace-1843")
    grace_token = suite.login("grace", "hopper-cobol-7")
    print("[Auth] Ada and Grace logged in.")

    # Operations are impossible without authentication.
    try:
        suite.create_canvas("not-a-real-token", "ghost")
        raise AssertionError("expected AuthenticationError")
    except AuthenticationError as exc:
        print("[Auth] Anonymous canvas creation blocked:", exc)

    # -- Requirement 2: real-time collaboration canvas --------------------
    canvas_id = suite.create_canvas(ada_token, "Marketing Banner")
    print(f"\n[Canvas] Ada created canvas {canvas_id}.")

    # Grace subscribes to live updates; we capture the events she receives.
    grace_inbox: List[Event] = []
    suite.join_canvas(grace_token, canvas_id, on_event=grace_inbox.append)
    print("[Canvas] Grace joined and is now subscribed to live updates.")
    print("[Canvas] Participants:", suite.participants(ada_token, canvas_id))

    # -- Requirement 6 (runtime): texture before any shape is rejected ----
    try:
        suite.apply_texture(ada_token, canvas_id, "el_missing", Texture.solid("red"))
        raise AssertionError("expected DependencyError")
    except DependencyError as exc:
        print("\n[Dependency] Texture-before-shape blocked:", exc)

    # -- Requirement 3: shape & texture tools -----------------------------
    rect = suite.add_shape(
        ada_token, canvas_id, "rectangle", x=0, y=0, width=120, height=60, name="bg"
    )
    circle = suite.add_shape(
        ada_token, canvas_id, "circle", cx=200, cy=40, radius=30, name="badge"
    )
    triangle = suite.add_shape(
        ada_token,
        canvas_id,
        "polygon",
        points=[(300, 0), (360, 0), (330, 60)],
        name="arrow",
    )
    print("\n[Shapes] Ada added a rectangle, a circle and a triangle.")

    suite.apply_texture(ada_token, canvas_id, rect, Texture.solid("#3366FF"))
    suite.apply_texture(
        ada_token, canvas_id, circle, Texture.gradient(["#FF0000", "#FFAA00"], angle=45)
    )
    suite.apply_texture(
        ada_token, canvas_id, triangle, Texture.pattern("stripes", color="blue")
    )
    print("[Textures] Solid, gradient and pattern textures applied.")

    # Grace must have been notified about all of the above in real time.
    added = [e for e in grace_inbox if e.type is EventType.ELEMENT_ADDED]
    textured = [e for e in grace_inbox if e.type is EventType.TEXTURE_APPLIED]
    assert len(added) == 3, added
    assert len(textured) == 3, textured
    print(f"[Real-time] Grace received {len(grace_inbox)} live events "
          f"({len(added)} adds, {len(textured)} textures).")

    # -- Requirement 4: element management --------------------------------
    suite.align_elements(ada_token, canvas_id, [rect, circle, triangle], Alignment.TOP)
    print("\n[Organize] Aligned all shapes to the top edge.")
    tops = {
        el.name: round(el.bounding_box().min_y, 3)
        for el in suite._get_canvas(canvas_id).elements_in_order()
    }
    assert len(set(tops.values())) == 1, tops
    print("[Organize] Verified equal top coordinates:", tops)

    group_id = suite.group_elements(
        ada_token, canvas_id, [rect, circle, triangle], name="logo"
    )
    print(f"[Organize] Grouped the shapes into {group_id}.")

    suite.arrange_element(ada_token, canvas_id, rect, Arrange.BRING_TO_FRONT)
    front = suite._get_canvas(canvas_id).elements_in_order()[-1]
    assert front.id == rect, front
    print("[Organize] Brought the rectangle to the front; "
          f"front element is now '{front.name}'.")

    # -- Requirement 5: annotations & comments ----------------------------
    ann_id = suite.add_annotation(
        grace_token, canvas_id, "Can we make the badge bigger?", element_id=circle
    )
    suite.reply_annotation(ada_token, canvas_id, ann_id, "Sure, bumping the radius.")
    print("\n[Annotate] Grace left a comment; Ada replied.")
    annotations = suite.list_annotations(ada_token, canvas_id)
    assert annotations[0]["replies"], annotations
    print("[Annotate] Thread:",
          annotations[0]["text"], "->", annotations[0]["replies"][0]["text"])

    suite.resolve_annotation(ada_token, canvas_id, ann_id)
    open_threads = suite.list_annotations(ada_token, canvas_id, include_resolved=False)
    assert open_threads == [], open_threads
    print("[Annotate] Annotation resolved; open threads:", len(open_threads))

    # -- Authorization: a non-participant cannot edit ---------------------
    suite.register("eve", "outsider-99")
    eve_token = suite.login("eve", "outsider-99")
    try:
        suite.add_shape(eve_token, canvas_id, "circle", cx=0, cy=0, radius=5)
        raise AssertionError("expected AuthorizationError")
    except AuthorizationError as exc:
        print("\n[Auth] Non-participant edit blocked:", exc)

    # -- Final state ------------------------------------------------------
    snapshot = suite.export_canvas(ada_token, canvas_id)
    print("\n[Export] Canvas snapshot:")
    print(f"  name         : {snapshot['name']}")
    print(f"  elements     : {len(snapshot['elements'])}")
    print(f"  groups       : {len(snapshot['groups'])}")
    print(f"  annotations  : {len(snapshot['annotations'])}")
    print(f"  participants : {snapshot['participants']}")
    print("\n[Features] Enabled capabilities:", suite.feature_status())

    print("\nAll demonstration assertions passed. \u2713")


if __name__ == "__main__":
    _demo()
